'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { useTheme } from '@/hooks/useTheme';
import { useAppStore } from '@/store';
import Image from 'next/image';
import { usePathname } from 'next/navigation';
import { Menu } from 'lucide-react';

export default function Navbar() {
  const pathname = usePathname();
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [showShadow, setShowShadow] = useState(false);
  const { theme, changeTheme } = useTheme();
  const { currentUser } = useAppStore();
  const isHome = pathname === '/';

  useEffect(() => {
    const handleScroll = () => {
      setShowShadow(window.scrollY > 10);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const getBgColor = () => {
    if (isHome) return 'bg-transparent';

    if (!theme || theme === 'dark') {
      return 'bg-gray-900';
    }

    switch (theme) {
      case 'water':
        return 'bg-gradient-to-r from-blue-950 to-blue-900';
      case 'fire':
        return 'bg-gradient-to-r from-red-950 to-red-900';
      case 'grass':
        return 'bg-gradient-to-r from-green-950 to-green-900';
      default:
        return 'bg-gray-900';
    }
  };

  const getActiveNavStyle = () => {
    if (!theme || theme === 'dark') {
      return 'text-white bg-gray-800';
    }

    switch (theme) {
      case 'water':
        return 'text-white bg-blue-800';
      case 'fire':
        return 'text-white bg-red-800';
      case 'grass':
        return 'text-white bg-green-800';
      default:
        return 'text-white bg-gray-800';
    }
  };

  const getInactiveNavStyle = () => {
    return 'text-gray-300 hover:text-white transition-colors';
  };

  const getAvatarBgColor = () => {
    if (!currentUser?.team) return 'bg-gray-800';

    switch (currentUser.team) {
      case 'acqua':
        return 'bg-blue-800';
      case 'fuoco':
        return 'bg-red-800';
      case 'erba':
        return 'bg-green-800';
      default:
        return 'bg-gray-800';
    }
  };

  return (
    <div className={`sticky top-0 left-0 right-0 z-50 transition-all duration-300`}>
      <div className={`${getBgColor()}${showShadow ? ' shadow-lg' : ''}`}>
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-[70px]">
            <div className="flex items-center">
              <Link
                href="/"
                className="flex-shrink-0 flex items-center"
              >
                <Image
                  src="/images/42-logo-black.png"
                  alt="42"
                  width={50}
                  height={50}
                  className={`${isHome ? 'block' : 'hidden'} h-[48px] w-[48px] dark:invert`}
                />
                <Image
                  src="/images/42-logo-black.png"
                  alt="42"
                  width={50}
                  height={50}
                  className={`${isHome ? 'hidden' : 'block'} h-[48px] w-[48px] dark:invert`}
                />
              </Link>
              <div className="hidden lg:flex items-center ml-8 space-x-4">
                <Link
                  href="/dashboard"
                  className={`px-4 py-[14px] rounded-md text-[16px] font-medium ${
                    pathname === '/dashboard' 
                      ? getActiveNavStyle() 
                      : getInactiveNavStyle()
                  }`}
                >
                  Dashboard
                </Link>
                <Link
                  href="/eventi"
                  className={`px-4 py-[14px] rounded-md text-[16px] font-medium ${
                    pathname === '/eventi' 
                      ? getActiveNavStyle() 
                      : getInactiveNavStyle()
                  }`}
                >
                  Eventi
                </Link>
                <Link
                  href="/classifica"
                  className={`px-4 py-[14px] rounded-md text-[16px] font-medium ${
                    pathname === '/classifica' 
                      ? getActiveNavStyle() 
                      : getInactiveNavStyle()
                  }`}
                >
                  Classifica
                </Link>
                <Link
                  href="/club"
                  className={`px-4 py-[14px] rounded-md text-[16px] font-medium ${
                    pathname === '/club' 
                      ? getActiveNavStyle() 
                      : getInactiveNavStyle()
                  }`}
                >
                  Club
                </Link>
                {currentUser?.isAdmin && (
                  <Link
                    href="/admin"
                    className={`px-4 py-[14px] rounded-md text-[16px] font-medium ${
                      pathname === '/admin' 
                        ? getActiveNavStyle() 
                        : getInactiveNavStyle()
                    }`}
                  >
                    Admin
                  </Link>
                )}
              </div>
            </div>

            <div className="flex items-center">
              {/* Selettore tema */}
              <div className="hidden sm:flex space-x-2 mr-4">
                <button 
                  onClick={() => changeTheme('water')}
                  className={`h-[35px] w-[35px] rounded-full bg-blue-600 ${theme === 'water' ? 'ring-2 ring-blue-400' : ''}`}
                  aria-label="Tema Acqua"
                />
                <button 
                  onClick={() => changeTheme('fire')}
                  className={`h-[35px] w-[35px] rounded-full bg-red-600 ${theme === 'fire' ? 'ring-2 ring-red-400' : ''}`}
                  aria-label="Tema Fuoco"
                />
                <button 
                  onClick={() => changeTheme('grass')}
                  className={`h-[35px] w-[35px] rounded-full bg-green-600 ${theme === 'grass' ? 'ring-2 ring-green-400' : ''}`}
                  aria-label="Tema Erba"
                />
              </div>

              {/* Avatar utente */}
              <div className="ml-4 flex items-center">
                <div className={`h-[35px] w-[35px] rounded-full ${getAvatarBgColor()} flex items-center justify-center text-white font-bold text-lg`}>
                  {currentUser?.username?.charAt(0).toUpperCase() || 'U'}
                </div>
              </div>

              {/* Menu mobile hamburger */}
              <div className="flex lg:hidden ml-4">
                <button
                  type="button"
                  className="p-2 rounded-md text-gray-300 hover:text-white"
                  onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
                >
                  <Menu className="h-6 w-6" />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Menu mobile */}
      {mobileMenuOpen && (
        <div className={`lg:hidden ${getBgColor()} border-t border-gray-700`}>
          <div className="px-2 pt-2 pb-3 space-y-1">
            <Link
              href="/dashboard"
              className={`block px-3 py-2 rounded-md text-base font-medium ${
                pathname === '/dashboard' 
                  ? getActiveNavStyle() 
                  : getInactiveNavStyle()
              }`}
              onClick={() => setMobileMenuOpen(false)}
            >
              Dashboard
            </Link>
            <Link
              href="/eventi"
              className={`block px-3 py-2 rounded-md text-base font-medium ${
                pathname === '/eventi' 
                  ? getActiveNavStyle() 
                  : getInactiveNavStyle()
              }`}
              onClick={() => setMobileMenuOpen(false)}
            >
              Eventi
            </Link>
            <Link
              href="/classifica"
              className={`block px-3 py-2 rounded-md text-base font-medium ${
                pathname === '/classifica' 
                  ? getActiveNavStyle() 
                  : getInactiveNavStyle()
              }`}
              onClick={() => setMobileMenuOpen(false)}
            >
              Classifica
            </Link>
            <Link
              href="/club"
              className={`block px-3 py-2 rounded-md text-base font-medium ${
                pathname === '/club' 
                  ? getActiveNavStyle() 
                  : getInactiveNavStyle()
              }`}
              onClick={() => setMobileMenuOpen(false)}
            >
              Club
            </Link>
            {currentUser?.isAdmin && (
              <Link
                href="/admin"
                className={`block px-3 py-2 rounded-md text-base font-medium ${
                  pathname === '/admin' 
                    ? getActiveNavStyle() 
                    : getInactiveNavStyle()
                }`}
                onClick={() => setMobileMenuOpen(false)}
              >
                Admin
              </Link>
            )}
            
            {/* Selettore tema mobile */}
            <div className="px-3 py-2 mt-3">
              <p className="text-gray-300 text-sm mb-2">Seleziona tema:</p>
              <div className="flex space-x-3">
                <button 
                  onClick={() => {
                    changeTheme('water');
                    setMobileMenuOpen(false);
                  }}
                  className={`h-[35px] w-[35px] rounded-full bg-blue-600 ${theme === 'water' ? 'ring-2 ring-blue-400' : ''}`}
                  aria-label="Tema Acqua"
                />
                <button 
                  onClick={() => {
                    changeTheme('fire');
                    setMobileMenuOpen(false);
                  }}
                  className={`h-[35px] w-[35px] rounded-full bg-red-600 ${theme === 'fire' ? 'ring-2 ring-red-400' : ''}`}
                  aria-label="Tema Fuoco"
                />
                <button 
                  onClick={() => {
                    changeTheme('grass');
                    setMobileMenuOpen(false);
                  }}
                  className={`h-[35px] w-[35px] rounded-full bg-green-600 ${theme === 'grass' ? 'ring-2 ring-green-400' : ''}`}
                  aria-label="Tema Erba"
                />
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
} 